-- ============================================================
-- 073 Seed EO Global Speakers Academy speakers
-- ============================================================
-- Loads 92 speakers from the EO Global Speakers Academy
-- public database into public.public_speakers.
--
-- Source: https://event.eonetwork.org/global-speakers-academy/database/
-- Extracted to supabase/../eo_global_speakers_academy_database.xlsx
-- and converted to SQL for git tracking.
--
-- Idempotent via the (source, lower(name)) unique index from 072.
-- Re-running this migration does nothing for already-loaded rows;
-- a future migration can do an explicit UPDATE if GSA refreshes a entry.

on conflict (source, lower(name)) do nothing;

notify pgrst, 'reload schema';
